diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..6e695e8b4634 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -3552,6 +3552,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
           }
       }
     }
+
     [[fallthrough]];
   }
   case Intrinsic::vector_reduce_xor: {
@@ -3734,6 +3735,34 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   }
   }

+  // Handle funnel shifts with zero operands when the shift amount is known
+  // to be less than the bit width.
+  // fshl(X, 0, Y) -> shl X, Y
+  // fshr(0, X, Y) -> lshr X, Y
+  if (IID == Intrinsic::fshl || IID == Intrinsic::fshr) {
+    Value *Op0 = II->getArgOperand(0);
+    Value *Op1 = II->getArgOperand(1);
+    Value *ShAmt = II->getArgOperand(2);
+    unsigned BitWidth = Op0->getType()->getScalarSizeInBits();
+
+    // Check if the shift amount is known to be less than the bit width.
+    const APInt *C;
+    bool IsValidShiftAmt = false;
+    if (match(ShAmt, m_APInt(C))) {
+      IsValidShiftAmt = C->ult(BitWidth);
+    } else {
+      KnownBits KB = computeKnownBits(ShAmt, 0, II);
+      IsValidShiftAmt = KB.getMaxValue().ult(BitWidth);
+    }
+
+    if (IsValidShiftAmt) {
+      if (IID == Intrinsic::fshl && match(Op1, m_Zero()))
+        return BinaryOperator::Create(Instruction::Shl, Op0, ShAmt);
+      if (IID == Intrinsic::fshr && match(Op0, m_Zero()))
+        return BinaryOperator::Create(Instruction::LShr, Op1, ShAmt);
+    }
+  }
+
   // Try to fold intrinsic into select operands. This is legal if:
   //  * The intrinsic is speculatable.
   //  * The select condition is not a vector, or the intrinsic does not
@@ -3753,6 +3782,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   return visitCallBase(*II);
 }

+
 // Fence instruction simplification
 Instruction *InstCombinerImpl::visitFenceInst(FenceInst &FI) {
   auto *NFI = dyn_cast<FenceInst>(FI.getNextNonDebugInstruction());

